def normalize_email(email: str) -> str:
    return email.strip().lower()


def bad_request(message, fields=None, status=400):
    payload = {"error": message}
    if fields:
        payload["fields"] = fields
    return jsonify(payload), status


@app.post("/api/profile")
def update_profile():
    user = current_user()
    if not user:
        return jsonify({"error": "unauthorized"}), 401

    data = request.get_json(silent=True)
    if data is None:
        return bad_request("expected application/json body")

    allowed_keys = {"email", "password", "two_factor"}
    unknown = sorted(set(data.keys()) - allowed_keys)
    if unknown:
        return bad_request("unknown fields", {"unknown": unknown})

    updates = {}
    field_errors = {}

    if "email" in data:
        email = data.get("email")
        if not isinstance(email, str) or not email.strip():
            field_errors["email"] = "must be a non-empty string"
        else:
            email_n = normalize_email(email)
            if not EMAIL_RE.match(email_n):
                field_errors["email"] = "invalid email format"
            else:
                updates["email"] = email_n

    if "password" in data:
        password = data.get("password")
        if not isinstance(password, str) or len(password) < 8:
            field_errors["password"] = "must be a string with at least 8 characters"
        else:
            updates["password_hash"] = generate_password_hash(password)

    if "two_factor" in data:
        tf = data.get("two_factor")
        if not isinstance(tf, dict):
            field_errors["two_factor"] = "must be an object"
        else:
            enabled = tf.get("enabled", None)
            method = tf.get("method", None)

            if enabled is None or not isinstance(enabled, bool):
                field_errors["two_factor.enabled"] = "must be a boolean"
            else:
                if enabled:
                    if method not in ("totp", "sms"):
                        field_errors["two_factor.method"] = "must be one of: totp, sms"
                    else:
                        updates["two_factor_enabled"] = True
                        updates["two_factor_method"] = method
                else:
                    updates["two_factor_enabled"] = False
                    updates["two_factor_method"] = None

    if field_errors:
        return bad_request("validation error", field_errors, status=422)

    if not updates:
        return bad_request("no updatable fields provided")

    updated = users.update(user["id"], updates)
    if not updated:
        return jsonify({"error": "not found"}), 404

    return jsonify(
        {
            "id": updated["id"],
            "email": updated["email"],
            "two_factor": {
                "enabled": updated["two_factor_enabled"],
                "method": updated["two_factor_method"],
            },
            "updated_at": updated["updated_at"],
        }
    ), 200


